    wwv_flow_api.g_varchar2_table(283) := '0\pararsid16608725 {\rtlch\fcs1 \af1\afs20 \ltrch\fcs0 \f1\fs20\insrsid9180338\charrsid9180338 '||wwv_flow.LF||
'Dand';
    wwv_flow_api.g_varchar2_table(284) := 'o alcance a la solicitud de la referencia, le informamos  que de acuerdo al art\''edculo 187  del Est';
    wwv_flow_api.g_varchar2_table(285) := 'atuto Tributario Distrital los contribuyentes para actuar ante la Administraci\''f3n Tributaria Distr';
    wwv_flow_api.g_varchar2_table(286) := 'ital, podr\''e1'||wwv_flow.LF||
'n hacerlo personalmente o por medio de representantes legales, o apoderados legalment';
    wwv_flow_api.g_varchar2_table(287) := 'e constituidos, lo que significa que en su caso debe  acreditar ante este despacho legitimaci\''f3n c';
    wwv_flow_api.g_varchar2_table(288) := 'omo propietario del bien inmueble aunado '||wwv_flow.LF||
'al hecho que de conformidad  con el art\''edculo 849-4 del ';
    wwv_flow_api.g_varchar2_table(289) := 'Estatuto Tributario los expedientes tienen reserva legal.'||wwv_flow.LF||
'\par Finalmente, se le advierte al peticio';
    wwv_flow_api.g_varchar2_table(290) := 'nario  que la no respuesta  dentro del mes siguiente  al recibo de la presente dar\''e1 lugar a la ap';
    wwv_flow_api.g_varchar2_table(291) := 'licaci\''f3n del Art\''edculo 17 del C\''f3'||wwv_flow.LF||
'digo de Procedimiento Administrativo y de lo Contencioso Ad';
    wwv_flow_api.g_varchar2_table(292) := 'ministrativo (Ley 1755 del 30 de junio de 2015): }{\rtlch\fcs1 \af1\afs20 \ltrch\fcs0 \b\f1\fs20\ins';
    wwv_flow_api.g_varchar2_table(293) := 'rsid9180338\charrsid9180338 \''93Peticiones incompletas y }{\rtlch\fcs1 \af1\afs20 \ltrch\fcs0 '||wwv_flow.LF||
'\f1\f';
    wwv_flow_api.g_varchar2_table(294) := 's20\insrsid9180338\charrsid9180338 desistimiento t\''e1cito. En virtud del principio de eficacia, cua';
    wwv_flow_api.g_varchar2_table(295) := 'ndo la autoridad constate que una}{\rtlch\fcs1 \af1\afs20 \ltrch\fcs0 \b\f1\fs20\insrsid9180338\char';
    wwv_flow_api.g_varchar2_table(296) := 'rsid9180338  petici\''f3n ya radicada est\''e1'||wwv_flow.LF||
' incompleta o que el peticionario deba realizar una ges';
    wwv_flow_api.g_varchar2_table(297) := 'ti\''f3n de tr\''e1mite a su cargo, necesaria para adoptar una decisi\''f3n de fondo, y que la actuaci\';
    wwv_flow_api.g_varchar2_table(298) := '''f3n pueda continuar sin oponerse a la ley, requerir\''e1 al peticionario dentro de los diez (10) d'||wwv_flow.LF||
'\';
    wwv_flow_api.g_varchar2_table(299) := '''edas siguientes a la fecha de radicaci\''f3n para que la complete en el t\''e9rmino m\''e1ximo de un (';
    wwv_flow_api.g_varchar2_table(300) := '1) mes. '||wwv_flow.LF||
'\par A partir del d\''eda siguiente en que el interesado aporte los documentos o informes re';
    wwv_flow_api.g_varchar2_table(301) := 'queridos, comenzar\''e1 a correr el t\''e9rmino para resolver la petici\''f3n. '||wwv_flow.LF||
'\par Se entender\''e1 qu';
    wwv_flow_api.g_varchar2_table(302) := 'e el peticionario ha desistido de su solicitud o de la actuaci\''f3n cuando no satisfaga el requerimi';
    wwv_flow_api.g_varchar2_table(303) := 'ento, salvo que antes de vencer el plazo concedido solicite pr\''f3rroga hasta por un t\''e9rmino igua';
    wwv_flow_api.g_varchar2_table(304) := 'l. '||wwv_flow.LF||
'\par Vencidos los t\''e9rminos establecidos en este art\''edculo, sin que el peticionario haya cum';
    wwv_flow_api.g_varchar2_table(305) := 'plido el requerimiento, la autoridad decretar\''e1 el desistimiento y el archivo del expediente, medi';
    wwv_flow_api.g_varchar2_table(306) := 'ante acto administrativo motivado, que se notificar\''e1'||wwv_flow.LF||
' personalmente, contra el cual \''fanicamente';
    wwv_flow_api.g_varchar2_table(307) := ' procede recurso de reposici\''f3n, sin perjuicio de que la respectiva solicitud pueda ser nuevamente';
    wwv_flow_api.g_varchar2_table(308) := ' presentada con el lleno de los requisitos legales.\''94'||wwv_flow.LF||
'\par }\pard \ltrpar\ql \li0\ri0\sa160\widctl';
